package grammars

func init() {
	Register(LangEntry{
		Name:           "nim",
		Extensions:     []string{".nim", ".nims"},
		Language:       NimLanguage,
		GrammarSource:  GrammarSourceTS2GoBlob,
		HighlightQuery: "; SPDX-FileCopyrightText: 2023 Leorize <leorize+oss@disroot.org>\n; SPDX-License-Identifier: MPL-2.0\n\n; Punctuations\n[ \".\" \";\" \",\" \":\" ] @punctuation.delimiter\n[ \"(\" \")\" \"[\" \"]\" \"{\" \"}\" \"{.\" \".}\" ] @punctuation.bracket\n\n; Operator by default, but could be overriden\n[ \"=\" ] @operator\n\n; Special\n(blank_identifier) @variable.builtin\n\n; Calls\n(call\n  function: [\n    (identifier) @function.call\n    (dot_expression\n      right: (identifier) @function.call)\n  ])\n(generalized_string\n  function: [\n    (identifier) @function.call\n    (dot_expression\n      right: (identifier) @function.call)\n  ])\n\n; Declarations\n(exported_symbol \"*\" @type.qualifier)\n(_ \"=\" @punctuation.delimiter [body: (_) value: (_)])\n(proc_declaration name: (_) @function)\n(func_declaration name: (_) @function)\n(converter_declaration name: (_) @function)\n(method_declaration name: (_) @method)\n(template_declaration name: (_) @function.macro)\n(macro_declaration name: (_) @function.macro)\n(symbol_declaration name: (_) @variable)\n(parameter_declaration\n  (symbol_declaration_list\n    (symbol_declaration name: (_) @parameter)))\n(_\n  [\n    type: [\n      (type_expression (identifier))\n      (type_expression (accent_quoted (identifier)))\n    ] @type\n    return_type: [\n      (type_expression (identifier))\n      (type_expression (accent_quoted (identifier)))\n    ] @type\n  ])\n\n; Exceptions\n[\n  \"try\"\n  \"except\"\n  \"finally\"\n  \"raise\"\n] @exception\n\n(except_branch values: (expression_list\n  [\n    (identifier) @type\n    (infix_expression\n      left: (identifier) @type\n      operator: \"as\"\n      right: (identifier) @variable)\n  ]))\n\n; Expressions\n(dot_expression\n  right: (identifier) @field)\n\n; Literal/comments\n[\n  (comment)\n  (block_comment)\n] @comment\n\n[\n  (documentation_comment)\n  (block_documentation_comment)\n] @comment.documentation\n\n(interpreted_string_literal) @string\n(long_string_literal) @string\n(raw_string_literal) @string\n(generalized_string) @string\n(char_literal) @character\n(escape_sequence) @string.escape\n(integer_literal) @number\n(float_literal) @float\n(custom_numeric_literal) @number\n(nil_literal) @constant.builtin\n\n; Keyword\n[\n  \"if\"\n  \"when\"\n  \"case\"\n  \"elif\"\n  \"else\"\n] @conditional\n\n(of_branch \"of\" @conditional)\n\n[\n  \"import\"\n  \"include\"\n  \"export\"\n] @include\n\n(import_from_statement \"from\" @include)\n(except_clause \"except\" @include)\n\n[\n  \"for\"\n  \"while\"\n  \"continue\"\n  \"break\"\n] @repeat\n\n(for \"in\" @repeat)\n\n[\n  \"macro\"\n  \"template\"\n  \"const\"\n  \"let\"\n  \"var\"\n  \"asm\"\n  \"bind\"\n  \"block\"\n  \"concept\"\n  \"defer\"\n  \"discard\"\n  \"distinct\"\n  \"do\"\n  \"enum\"\n  \"mixin\"\n  \"nil\"\n  \"object\"\n  \"out\"\n  \"ptr\"\n  \"ref\"\n  \"static\"\n  \"tuple\"\n  \"type\"\n] @keyword\n\n[\n  \"proc\"\n  \"func\"\n  \"method\"\n  \"converter\"\n  \"iterator\"\n] @keyword.function\n\n[\n  \"and\"\n  \"or\"\n  \"xor\"\n  \"not\"\n  \"div\"\n  \"mod\"\n  \"shl\"\n  \"shr\"\n  \"from\"\n  \"as\"\n  \"of\"\n  \"in\"\n  \"notin\"\n  \"is\"\n  \"isnot\"\n  \"cast\"\n] @keyword.operator\n\n[\n  \"return\"\n  \"yield\"\n] @keyword.return\n\n; Operators\n(infix_expression operator: _ @operator)\n(prefix_expression operator: _ @operator)\n\n",
	})
}
